pauli_stabilizers = [stim.PauliString(s) for s in stabilizers]

try:
    tableau = stim.Tableau.from_stabilizers(pauli_stabilizers, allow_redundant=True, allow_underconstrained=True)
    circuit = tableau.to_circuit(method="graph_state")
    
    # Check if circuit has resets and replace them if needed
    # The requirement is that it preserves stabilizers.
    # The 'graph_state' method typically includes resets (R).
    # If the user's problem context allows resets, great.
    # If not, and the input is |0>, we can remove the initial resets.
    
    # We will print the circuit as is, then maybe post-process in another step if needed.
    
    print(circuit)
except Exception as e:
    print(f"Error: {e}")
